const now = new Date();
const runId = `contract-${now.toISOString().replace(/[-:.TZ]/g, '').slice(0, 14)}-${Math.random().toString(16).slice(2, 8)}`;
return [{
  json: {
    bucketName: 'your-contract-bucket',
    incomingPrefix: 'contracts/incoming/',
    processedPrefix: 'contracts/processed/',
    errorPrefix: 'contracts/errors/',
    apiBaseUrl: 'https://your-billing-api.example.com',
    apiToken: '',
    runId,
    startedAt: now.toISOString()
  }
}];

const rows = $input.all();
const config = $('Build Config').first().json;
const accepted = ['.pdf', '.txt', '.md', '.docx'];
const normalizedRows = rows.flatMap((item) => {
  if (Array.isArray(item.json?.Contents)) {
    return item.json.Contents.map((entry) => ({ json: entry }));
  }
  if (Array.isArray(item.json?.files)) {
    return item.json.files.map((entry) => ({ json: entry }));
  }
  return [item];
});
const toKey = (item) => item.json.Key || item.json.key || item.json.name || item.json.fileName || item.json.path || '';
return normalizedRows
  .map((item) => {
    const fileName = toKey(item);
    const lower = fileName.toLowerCase();
    const matches = accepted.some((ext) => lower.endsWith(ext));
    return {
      json: {
        ...config,
        fileName,
        s3Key: fileName,
        fileExt: accepted.find((ext) => lower.endsWith(ext)) || '',
        partnerHint: fileName.split('/').pop().replace(/\.[^.]+$/, '') || '',
        ingestStatus: matches ? 'queued' : 'skipped'
      }
    };
  })
  .filter((item) => item.json.ingestStatus === 'queued');

const config = $('Build Config').first().json;
const fileName = $json.fileName || $json.s3Key || '';
const binaryKeys = Object.keys($binary || {});
const binary = binaryKeys.length ? $binary[binaryKeys[0]] : null;
const isPdf = /\.pdf$/i.test(fileName);
let contractText = '';
if (!isPdf && binary && binary.data) {
  contractText = Buffer.from(binary.data, 'base64').toString('utf8');
}
return [{
  json: {
    ...config,
    ...$json,
    fileName,
    sourceType: 's3_contract_drop',
    parserStatus: isPdf ? 'needs-pdf-extraction' : (contractText ? 'ready' : 'empty'),
    contractText,
    extractedAt: new Date().toISOString()
  }
}];
